import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"中国国家博物馆","description":"","frontmatter":{},"headers":[],"relativePath":"museums/national-museum.md","filePath":"museums/national-museum.md","lastUpdated":null}'),n={name:"museums/national-museum.md"};function i(d,t,o,s,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="中国国家博物馆" tabindex="-1">中国国家博物馆 <a class="header-anchor" href="#中国国家博物馆" aria-label="Permalink to &quot;中国国家博物馆&quot;">​</a></h1><blockquote><p>&quot;世界上建筑面积最大的博物馆，中华文明的总汇。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>中国国家博物馆（简称国博）位于天安门广场东侧，是代表国家收藏、研究、展示、阐释中华文化代表性物证的最高历史文化艺术殿堂，也是世界上单体建筑面积最大的博物馆。国博现有藏品140余万件（套），涵盖古代文物、近现代文物、艺术品等多种门类。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-17:00（周一闭馆，节假日除外）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">国博官网、微信公众号、APP</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线天安门东站D口</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区东长安街16号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="创建" tabindex="-1">创建 <a class="header-anchor" href="#创建" aria-label="Permalink to &quot;创建&quot;">​</a></h3><p>中国国家博物馆的历史可追溯至1912年。时任教育总长蔡元培主持成立国立历史博物馆筹备处，这是中国第一个国立博物馆。</p><h3 id="发展历程" tabindex="-1">发展历程 <a class="header-anchor" href="#发展历程" aria-label="Permalink to &quot;发展历程&quot;">​</a></h3><ul><li><strong>1926年</strong>：国立历史博物馆正式开放</li><li><strong>1959年</strong>：中国历史博物馆和中国革命博物馆在天安门广场东侧建成</li><li><strong>2003年</strong>：中国历史博物馆和中国革命博物馆合并，组建中国国家博物馆</li><li><strong>2011年</strong>：新馆建成开放，成为世界上建筑面积最大的博物馆</li></ul><h3 id="新馆建设" tabindex="-1">新馆建设 <a class="header-anchor" href="#新馆建设" aria-label="Permalink to &quot;新馆建设&quot;">​</a></h3><p>2007年，国博启动改扩建工程。新馆由德国gmp建筑事务所设计，建筑面积近20万平方米，展厅面积约6.5万平方米，于2011年3月竣工开放。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="外观设计" tabindex="-1">外观设计 <a class="header-anchor" href="#外观设计" aria-label="Permalink to &quot;外观设计&quot;">​</a></h3><p>国博新馆建筑由两部分组成：原有的历史博物馆建筑（1959年建成）和新建的北扩部分。建筑外观庄重大气，与天安门广场的整体风格协调统一。</p><h4 id="立面设计" tabindex="-1">立面设计 <a class="header-anchor" href="#立面设计" aria-label="Permalink to &quot;立面设计&quot;">​</a></h4><ul><li><strong>柱廊</strong>：入口有34根高大的廊柱</li><li><strong>墙面</strong>：浅黄色石材，庄重典雅</li><li><strong>屋顶</strong>：平顶设计，与人民大会堂遥相呼应</li></ul><h3 id="内部空间" tabindex="-1">内部空间 <a class="header-anchor" href="#内部空间" aria-label="Permalink to &quot;内部空间&quot;">​</a></h3><p>国博内部空间宏大，展厅众多。主要展厅包括：</p><ul><li><strong>中央大厅</strong>：高33米，面积2000平方米</li><li><strong>展厅</strong>：48个展厅，总面积6.5万平方米</li><li><strong>剧场</strong>：可容纳800人的剧场</li><li><strong>学术报告厅</strong>：用于学术交流活动</li></ul><h2 id="常设展览" tabindex="-1">常设展览 <a class="header-anchor" href="#常设展览" aria-label="Permalink to &quot;常设展览&quot;">​</a></h2><h3 id="古代中国" tabindex="-1">古代中国 <a class="header-anchor" href="#古代中国" aria-label="Permalink to &quot;古代中国&quot;">​</a></h3><p>「古代中国」是国博最重要的基本陈列，以王朝更替为主要脉络，展示从远古时期到清代的中国历史发展进程。</p><h4 id="展览内容" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容" aria-label="Permalink to &quot;展览内容&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">展厅</th><th style="text-align:left;">时代</th><th style="text-align:left;">重点展品</th></tr></thead><tbody><tr><td style="text-align:left;">远古时期</td><td style="text-align:left;">旧石器-新石器</td><td style="text-align:left;">元谋人牙齿、山顶洞人骨针、仰韶彩陶</td></tr><tr><td style="text-align:left;">夏商西周</td><td style="text-align:left;">约前2070-前771</td><td style="text-align:left;">后母戊鼎、四羊方尊、大盂鼎</td></tr><tr><td style="text-align:left;">春秋战国</td><td style="text-align:left;">前770-前221</td><td style="text-align:left;">吴王夫差矛、曾侯乙编钟</td></tr><tr><td style="text-align:left;">秦汉</td><td style="text-align:left;">前221-220</td><td style="text-align:left;">兵马俑、金缕玉衣、击鼓说唱俑</td></tr><tr><td style="text-align:left;">三国两晋南北朝</td><td style="text-align:left;">220-589</td><td style="text-align:left;">青瓷、佛像</td></tr><tr><td style="text-align:left;">隋唐五代</td><td style="text-align:left;">581-960</td><td style="text-align:left;">唐三彩、法门寺地宫文物</td></tr><tr><td style="text-align:left;">辽宋夏金元</td><td style="text-align:left;">907-1368</td><td style="text-align:left;">汝窑瓷器、青花</td></tr><tr><td style="text-align:left;">明清</td><td style="text-align:left;">1368-1911</td><td style="text-align:left;">永乐大典、故宫文物</td></tr></tbody></table><h4 id="镇馆之宝" tabindex="-1">镇馆之宝 <a class="header-anchor" href="#镇馆之宝" aria-label="Permalink to &quot;镇馆之宝&quot;">​</a></h4><ol><li><strong>后母戊鼎</strong>：商代青铜器，世界最大青铜器</li><li><strong>四羊方尊</strong>：商代青铜器，工艺精湛</li><li><strong>击鼓说唱俑</strong>：东汉陶俑，生动传神</li><li><strong>金缕玉衣</strong>：汉代皇帝殓服</li></ol><h3 id="复兴之路" tabindex="-1">复兴之路 <a class="header-anchor" href="#复兴之路" aria-label="Permalink to &quot;复兴之路&quot;">​</a></h3><p>「复兴之路」展览展示1840年鸦片战争以来中国人民争取民族独立、人民解放和国家富强、人民幸福的历史进程。</p><h4 id="展览内容-1" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容-1" aria-label="Permalink to &quot;展览内容&quot;">​</a></h4><ul><li>鸦片战争与近代中国的沉沦</li><li>辛亥革命与君主专制的终结</li><li>中国共产党的成立</li><li>抗日战争</li><li>新中国的成立</li><li>社会主义建设</li><li>改革开放</li></ul><h3 id="专题展览" tabindex="-1">专题展览 <a class="header-anchor" href="#专题展览" aria-label="Permalink to &quot;专题展览&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">展览名称</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">中国古代青铜器艺术</td><td style="text-align:left;">商周青铜器精品</td></tr><tr><td style="text-align:left;">中国古代瓷器艺术</td><td style="text-align:left;">历代瓷器珍品</td></tr><tr><td style="text-align:left;">中国古代玉器艺术</td><td style="text-align:left;">新石器时代至清代玉器</td></tr><tr><td style="text-align:left;">中国古代佛造像</td><td style="text-align:left;">佛教艺术精品</td></tr><tr><td style="text-align:left;">中国古代钱币</td><td style="text-align:left;">历代钱币</td></tr><tr><td style="text-align:left;">中国古代书画</td><td style="text-align:left;">历代书画名作</td></tr><tr><td style="text-align:left;">中国古代服饰文化</td><td style="text-align:left;">古代服饰演变</td></tr></tbody></table><h2 id="镇馆之宝详解" tabindex="-1">镇馆之宝详解 <a class="header-anchor" href="#镇馆之宝详解" aria-label="Permalink to &quot;镇馆之宝详解&quot;">​</a></h2><h3 id="后母戊鼎-商代" tabindex="-1">后母戊鼎（商代） <a class="header-anchor" href="#后母戊鼎-商代" aria-label="Permalink to &quot;后母戊鼎（商代）&quot;">​</a></h3><p>后母戊鼎（原称司母戊鼎）是商王祖庚或祖甲为祭祀其母戊所制，是世界迄今出土最大、最重的青铜器，享有&quot;镇国之宝&quot;的美誉。鼎高133厘米、口长110厘米、口宽79厘米，重832.84公斤。</p><h3 id="四羊方尊-商代" tabindex="-1">四羊方尊（商代） <a class="header-anchor" href="#四羊方尊-商代" aria-label="Permalink to &quot;四羊方尊（商代）&quot;">​</a></h3><p>四羊方尊是商代晚期青铜礼器，祭祀用品。尊四角各塑一羊，羊首与羊颈伸出器外，羊身与羊腿附着于尊腹部及圈足上。方尊肩饰高浮雕蛇身龙纹，工艺精湛。</p><h3 id="击鼓说唱俑-东汉" tabindex="-1">击鼓说唱俑（东汉） <a class="header-anchor" href="#击鼓说唱俑-东汉" aria-label="Permalink to &quot;击鼓说唱俑（东汉）&quot;">​</a></h3><p>击鼓说唱俑出土于四川成都天回山崖墓，高55厘米。俑袒胸露腹，着裤赤足，左臂挟鼓，右手举槌，笑容满面，神态生动，是汉代陶俑艺术的巅峰之作。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="预约须知" tabindex="-1">预约须知 <a class="header-anchor" href="#预约须知" aria-label="Permalink to &quot;预约须知&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前1-7天在国博官网、微信公众号或APP预约</li><li><strong>身份证件</strong>：入场需携带预约时使用的身份证原件</li><li><strong>安检严格</strong>：禁止携带打火机等违禁物品</li><li><strong>限流措施</strong>：国博每日限流，建议提前预约</li></ol><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>半日游路线（约4小时）</strong>：</p><p>北门入口 → 古代中国展厅（远古→夏商周→秦汉） → 镇馆之宝 → 复兴之路展厅 → 中央大厅 → 专题展览 → 文创商店 → 南门出口</p><p><strong>一日游路线（约6-8小时）</strong>：</p><p>北门入口 → 古代中国展厅（完整游览） → 午餐（国博餐厅） → 复兴之路展厅 → 青铜器专题展 → 瓷器专题展 → 玉器专题展 → 书画展 → 文创商店 → 天安门广场</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：周二至周四人相对较少</li><li><strong>讲解服务</strong>：可租借语音导览器（押金200元，租金10元），或参加免费讲解</li><li><strong>餐饮服务</strong>：地下一层有餐厅，价格适中</li><li><strong>文创商店</strong>：国博文创很有特色，可购买纪念品</li><li><strong>拍照注意</strong>：部分展品禁止拍照，注意标识</li><li><strong>存包服务</strong>：大件行李需寄存（免费）</li></ol><h3 id="周边游览" tabindex="-1">周边游览 <a class="header-anchor" href="#周边游览" aria-label="Permalink to &quot;周边游览&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">天安门广场</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">世界最大城市广场</td></tr><tr><td style="text-align:left;">人民大会堂</td><td style="text-align:center;">西侧</td><td style="text-align:left;">国家最高权力机关所在地</td></tr><tr><td style="text-align:left;">毛主席纪念堂</td><td style="text-align:center;">南侧</td><td style="text-align:left;">纪念毛泽东主席</td></tr><tr><td style="text-align:left;">正阳门</td><td style="text-align:center;">南侧</td><td style="text-align:left;">老北京城门</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">北侧</td><td style="text-align:left;">明清皇宫</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>中国国家博物馆是国家最高历史文化艺术殿堂，是中华文明的集中展示。正如习近平总书记所说：</p><blockquote><p>&quot;博物馆是保护和传承人类文明的重要殿堂，是连接过去、现在、未来的桥梁。&quot;</p></blockquote><p>国博不仅展示中华文明的灿烂成就，也承载着民族复兴的历史记忆，是了解中国历史文化的必到之处。</p><hr><p><strong>📍 地址</strong>：北京市东城区东长安街16号 <strong>📞 电话</strong>：010-65116400 <strong>🌐 官网</strong>：<a href="http://www.chnmuseum.cn" target="_blank" rel="noreferrer">www.chnmuseum.cn</a><strong>📱 预约</strong>：关注「国家博物馆」微信公众号预约</p>',59)])])}const u=e(n,[["render",i]]);export{f as __pageData,u as default};
